export const locationsByRegion = ukAuctionLocations.reduce((acc, loc) => {
  if (!acc[loc.region]) acc[loc.region] = [];
  acc[loc.region].push(loc);
  return acc;
}, {} as Record<string, AuctionLocation[]>);

export const locationBySlug = ukAuctionLocations.reduce((acc, loc) => {
  acc[loc.slug] = loc;
  return acc;
}, {} as Record<string, AuctionLocation>);
